<script lang="ts">
import type{PlaySession,ChatMessage,SessionSnapshot}from'@simbot/session';import Icon from'@simbot/ui/Icon.svelte';import{renderMarkdown}from'@simbot/ui/markdown';import{alternateForward}from'./card-library';import{toFactLine}from'./FactReceipt.svelte';import{presentNarrativeIssues}from'./narrative-issues';
let{session,version,greetings=[],cardName,userName='나',model,waiting=false,portraitFor,onchange,onerror=()=>{}}:{session:PlaySession;version:number;greetings?:string[];cardName:string;userName?:string;model:string;waiting?:boolean;portraitFor:(id:string,emotion?:string)=>string|null;onchange:()=>void;onerror?:(message:string)=>void}=$props();let editing=$state<string|null>(null),draft=$state(''),rerolling=$state(false),alternateIndex=$state(0),greetingIndex=$state(0),latest=$state.raw<SessionSnapshot|null>(null),lastSessionId=$state(''),live=$state(0),menuFor=$state<string|null>(null),issuesOpen=$state(false);$effect(()=>{void version;if(lastSessionId!==session.id){lastSessionId=session.id;alternateIndex=session.alternateCount;greetingIndex=Math.max(0,greetings.indexOf(session.messages[0]?.content??''));latest=null;issuesOpen=false;return;}if(alternateIndex>session.alternateCount)alternateIndex=session.alternateCount;});$effect(()=>session.subscribe(()=>{live+=1;}));let messages=$derived.by(()=>{void version;void live;return session.messages;}),facts=$derived.by(()=>{void version;void live;return session.lastLogs.map(toFactLine);}),narrativeWarning=$derived.by(()=>{void version;void live;const last=session.messages.at(-1);return last?.role==='assistant'?presentNarrativeIssues(last.content,session.narrativeIssues).warning:null;});const guard=(work:()=>Promise<void>)=>work().catch(e=>onerror(e instanceof Error?e.message:String(e)));function name(message:ChatMessage){return message.role==='user'?userName:cardName;}export function displayMacros(content:string,user:string,char:string){return content.replace(/{{\s*user\s*}}/gi,user).replace(/{{\s*char\s*}}/gi,char);}async function save(message:ChatMessage){if(draft.trim()&&draft!==message.content)await session.editMessage(message.id,draft);editing=null;onchange();}async function remove(message:ChatMessage,cascade=false){menuFor=null;if(!confirm(cascade?'이 메시지 이후를 전부 삭제할까요?':'이 메시지를 삭제할까요?'))return;await session.removeMessage(message.id,cascade);onchange();}async function left(){if(alternateIndex<=0)return;rerolling=true;try{if(alternateIndex===session.alternateCount)latest=session.snapshot();await session.showAlternate(--alternateIndex);onchange();}finally{rerolling=false;}}async function right(){rerolling=true;try{const action=alternateForward(alternateIndex,session.alternateCount);if(action.kind==='show'){alternateIndex=action.index;if(action.index===session.alternateCount&&latest){session.restore(latest);await session.save();}else await session.showAlternate(action.index);}else{await session.reroll();alternateIndex=session.alternateCount;latest=session.snapshot();}onchange();}finally{rerolling=false;}}async function rerollIssue(){rerolling=true;try{await session.reroll();alternateIndex=session.alternateCount;latest=session.snapshot();issuesOpen=false;onchange();}finally{rerolling=false;}}async function greeting(delta:number){greetingIndex=(greetingIndex+delta+greetings.length)%greetings.length;await session.replaceGreeting(greetings[greetingIndex]!);onchange();}
</script>
<div class="list">{#each messages as message,index(message.id)}<article class="message" class:user={message.role==='user'}><div class="avatar">{#if portraitFor(message.role==='assistant'?cardName:'user')}<img src={portraitFor(message.role==='assistant'?cardName:'user')!} alt=""/>{:else}{name(message).slice(0,1)}{/if}</div><div class="body"><div class="head"><strong>{name(message)}</strong>{#if message.role==='assistant'}<small>default</small>{/if}<div class="tools"><button title="편집" onclick={()=>{editing=message.id;draft=message.content;}}><Icon name="pencil"/></button><button title="복사" onclick={()=>navigator.clipboard.writeText(message.content)}><Icon name="copy"/></button><button title="삭제" onclick={()=>void guard(()=>remove(message))}><Icon name="trash"/></button><button title="더보기" onclick={()=>menuFor=menuFor===message.id?null:message.id}><Icon name="ellipsis"/></button>{#if menuFor===message.id}<div class="menu"><button onclick={()=>void guard(()=>remove(message,true))}>이 메시지 이후 전부 삭제</button></div>{/if}</div></div>{#if editing===message.id}<textarea bind:value={draft} onblur={()=>void save(message)}></textarea>{:else}<div class="text">{@html renderMarkdown(displayMacros(message.content,userName,cardName))}</div>{/if}{#if message.role==='assistant'}<div class="meta">{#if message.origin==='model'}<span class="model"><Icon name="bot" size={13}/>{model}</span>{/if}{#if messages.length===1&&greetings.length>1}<span class="swipe"><button onclick={()=>void guard(()=>greeting(-1))}><Icon name="left"/></button><b>{greetingIndex+1}/{greetings.length}</b><button onclick={()=>void guard(()=>greeting(1))}><Icon name="right"/></button></span>{:else if index===messages.length-1&&message.origin==='model'}<span class="swipe"><button disabled={rerolling||alternateIndex===0} onclick={()=>void guard(left)}><Icon name="left"/></button><b>{alternateIndex+1}/{session.alternateCount+1}</b><button disabled={rerolling||!session.checkpointDepth} onclick={()=>void guard(right)}><Icon name="refresh"/></button></span>{/if}</div>{/if}{#if message.role==='assistant'&&index===messages.length-1&&(facts.length||narrativeWarning)}<div class="chips">{#each facts as fact}<span class:rejected={fact.rejected}><Icon name={fact.rejected?'blocked':'star'} size={12}/><i>{fact.label}</i><b>{fact.delta??''}</b></span>{/each}{#if narrativeWarning}<button class="issue-chip" class:strong={narrativeWarning.strong} aria-expanded={issuesOpen} onclick={()=>issuesOpen=!issuesOpen}><Icon name="alert" size={12}/>{narrativeWarning.label}</button>{/if}</div>{#if narrativeWarning&&issuesOpen}<section class="issue-detail" class:strong={narrativeWarning.strong} aria-label="서사 검증 경고"><ul>{#each narrativeWarning.details as detail}<li>{detail}</li>{/each}</ul><button disabled={rerolling||!session.checkpointDepth} onclick={()=>void guard(rerollIssue)}><Icon name="refresh" size={13}/> 리롤</button></section>{/if}{/if}</div></article>{/each}{#if waiting}<article class="message typing" aria-label="응답 작성 중"><div class="avatar">{cardName.slice(0,1)}</div><div class="dots"><i></i><i></i><i></i></div></article>{/if}</div>
<style>.list{padding:26px 20px 120px}.message{display:grid;grid-template-columns:56px minmax(0,1fr);gap:16px;margin:0 auto 22px;max-width:900px}.avatar{width:56px;height:56px;border-radius:6px;background:#292d36;display:grid;place-items:center;font:700 20px sans-serif;overflow:hidden;box-shadow:0 2px 8px #0006}.avatar img{width:100%;height:100%;object-fit:cover}.head{display:flex;align-items:center;gap:8px;min-height:27px}.head strong{font-size:18px}.head small{font:10px ui-monospace;color:#858b98}.tools{margin-left:auto;display:flex;position:relative}.tools button,.swipe button{display:grid;place-items:center;border:0;background:transparent;color:#858b98;padding:4px;transition:.12s}.tools button:hover,.swipe button:hover{color:#78a2ff}.tools button:active,.swipe button:active{transform:scale(.9)}button:focus-visible{outline:2px solid #6c98f4;outline-offset:2px}.menu{position:absolute;right:0;top:100%;z-index:5;min-width:210px;padding:4px;border:1px solid #3a4150;border-radius:7px;background:#1c2029}.menu button{width:100%;padding:8px;color:#ddd}.text{color:#e7e0d4;font:15.5px/1.65 Georgia,'Noto Serif KR',serif}.user .text{font-family:system-ui,sans-serif;color:#d9dde7}.text :global(p){margin:2px 0 10px}.text :global(.dialogue){color:#e5bf79}.text :global(pre){overflow:auto;padding:12px;border-radius:7px;background:#0d0f13}.text :global(code){font:13px ui-monospace;background:#252932;padding:1px 4px;border-radius:3px}.text :global(blockquote){margin:8px 0;padding-left:12px;border-left:3px solid #6d7890;color:#b8bdc7}.text :global(a){color:#8fb3ff}.text :global(.illust){max-width:560px;margin:8px 0;border:1px solid #353942;border-radius:8px;overflow:hidden}.text :global(.illust img){display:block;width:100%;height:auto}.text :global(figcaption){padding:6px 10px;font:11px ui-monospace;color:#8d94a2}.body textarea{width:100%;min-height:110px;padding:10px;background:#191c22;color:#eee;border:1px solid #6793ef}.meta{display:flex;justify-content:flex-end;align-items:center;gap:12px;margin-top:5px;font:11px sans-serif;color:#727887}.model,.swipe{display:flex;align-items:center;gap:5px}.model{padding:3px 7px;border-radius:8px}.chips{display:flex;gap:6px;flex-wrap:wrap;margin-top:8px}.chips span{display:flex;align-items:center;gap:5px;border:1px solid #3b4149;border-left:2px solid #d8b36a;border-radius:5px;padding:3px 8px;font:11px ui-monospace;color:#dce0e6}.chips i{font-style:normal;color:#9299a7}.chips .rejected{border-left-color:#d06d55;color:#e0a7b0}.issue-chip{display:flex;align-items:center;gap:5px;border:1px solid #8d713c;border-left:2px solid #d8b36a;border-radius:5px;padding:3px 8px;background:#2c281f;color:#e3c78f;font:11px ui-monospace;cursor:pointer}.issue-chip.strong{border-color:#9c5048;background:#351f22;color:#f0aaa3}.issue-detail{margin-top:7px;padding:9px 11px;border:1px solid #806634;border-radius:6px;background:#242119;color:#d9c8a7;font:12px/1.5 sans-serif}.issue-detail.strong{border-color:#9c5048;background:#2e1d20;color:#efb3ad}.issue-detail ul{margin:0 0 8px;padding-left:18px}.issue-detail button{display:flex;align-items:center;gap:5px;border:1px solid currentColor;border-radius:5px;padding:4px 9px;background:transparent;color:inherit;cursor:pointer}.typing{align-items:center}.dots{display:flex;gap:5px;padding:20px 4px}.dots i{width:7px;height:7px;border-radius:50%;background:#8e96a6;animation:pulse 1s infinite}.dots i:nth-child(2){animation-delay:.15s}.dots i:nth-child(3){animation-delay:.3s}@keyframes pulse{50%{opacity:.25;transform:translateY(-3px)}}@media(prefers-reduced-motion:reduce){.dots i{animation:none}}@media(max-width:680px){.list{padding-inline:10px}.message{grid-template-columns:42px 1fr;gap:10px}.avatar{width:42px;height:42px}}</style>
